css:
.loader {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  color: #6366f1;
}
.loader span {
  width: 12px;
  height: 12px;
  border-radius: 999px;
  background: currentColor;
  animation: loader-bounce 0.75s ease-in-out infinite alternate;
}
.loader span:nth-child(2) { animation-delay: 0.15s; }
.loader span:nth-child(3) { animation-delay: 0.3s; }
@keyframes loader-bounce {
  from { transform: translateY(0); opacity: 0.55; }
  to { transform: translateY(-12px); opacity: 1; }
}
